INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('人力资源行政专员/助理 - 杭州（实习）', '互联网 / IT', '杭州', '民营企业', 120, 150, '1. 熟练使用Office办公软件及数据处理公式（vlookup）；2. 具备基本的数据处理能力', '有良好的沟通能力、执行力，工作细心，责任心强；对人力资源/行政工作有浓厚兴趣，具备较强的学习能力和适应能力', 1, '友好', '1. 负责招聘工作，发布招聘信息，筛选简历，安排面试；2. 负责员工五险一金的申报及费用核算；3. 负责办公室office的日常运维及固定资产的管理；4. 负责月度费用的申报与分摊工作，保证供应商费用的准确性；5. 负责协助组织公司员工活动与会议支持', '行政事务支持、招聘全流程执行、薪酬绩效支持、固定资产管理、会议活动组织', '本科及以上', '人力资源、行政管理等相关专业优先', '大三、大四实习生，每周实习5天，实习3个月及以上', '日常实习', '有人力资源管理师相关证书；有招聘、行政相关实习经验', '120-150元/天', '46111', '46129', 'https://www.shixiseng.com/intern/inn_9tcdmgx75hi?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）'), ('员工关系实习生 - 北京（实习）', '企业服务/咨询', '北京', '外资企业', 120, 150, '1. 熟练使用office办公软件；2. 具备一定的英文读写能力', '细心、踏实、执行力强、沟通能力良好', 1, '友好', '1. 负责办理员工的入离职和续签手续；2. 核算员工考勤和薪资；3. 申请开具员工的人事相关证明；4. 负责员工的日常管理支持；5. 完成领导安排的其他事务性工作', '员工关系支持、薪酬绩效支持、入离职手续办理', '统招本科及以上', '专业不限', '优先考虑24年毕业生，可实习6个月，每周可出勤4-5天，有相关实习经验优先', '日常实习', '有员工关系、人力资源相关实习经验；英语能力优秀', '120-150元/天', '45911', '46191', 'https://www.shixiseng.com/intern/inn_yyqicm9z4c4s?pcm=pc_SearchList', '员工关系类', '甲方（企业自有 HR 岗）'), ('员工关系实习生 - 上海（实习）', '餐饮/酒店/旅游/娱乐', '上海', '民营企业', 120, 200, '1. 有较强数字敏感性，熟练使用办公软件；2. 具备基础数据分析能力', '有较好的执行能力、沟通能力、逻辑思维能力，工作细致认真', 1, '友好', '1. 负责员工关系相关文书处理、台账整理、快递收寄等；2. 负责员工档案、文件交接归档；3. 负责系统资料整理、录入；4. 负责人事数据分析；5. 完成其他交办的工作', '员工关系支持、档案管理、招聘数据分析', '本科及以上', '法律、心理学、管理学、财务管理等优先', '可实习4个月，每周至少3天实习，有数据分析类工作经验优先', '日常实习', '有数据分析相关经验；法律/人力资源相关专业背景；员工关系相关实习经验', '120-200元/天', '45995', '46332', 'https://www.shixiseng.com/intern/inn_n34t5d3bmto?pcm=pc_SearchList', '员工关系类', '甲方（企业自有 HR 岗）'), ('员工关系实习生 - 广州（实习）', '金融/经济/投资/财会', '广州', '国企 / 央企', 80, 120, '熟练使用Office办公软件', '积极主动、乐于沟通，善于发现问题，工作认真负责', 1, '友好', '1. 协助员工入转调离的资料审核及数据整理；2. 协助员工档案的管理与维护；3. 协助人力资源部其他事务的运营工作', '员工关系支持、档案管理、入离职手续办理', '不限', '无强制专业限制', '可实习3个月，每周至少实习4天（可全勤实习优先），具备人力资源或行政类实习经验优先', '日常实习', '有人力资源、行政相关实习经验；金融行业相关实习经验', '100元/天', '45053', '46203', 'https://www.shixiseng.com/intern/inn_emsqd9hjbeh?pcm=pc_SearchList', '员工关系类', '甲方（企业自有 HR 岗）'), ('员工关系实习生 - 珠海（实习）', '互联网 / IT', '珠海', '民营企业', 100, 150, '1. 熟练使用Office办公软件；2. 具备基础的档案管理与数据整理能力', '对人力资源管理和员工关系有浓厚兴趣，具备一定的理论基础；细心、耐心、认真踏实，具备较强的责任心和保密意识', 1, '友好', '1. 员工入职管理：协助办理新员工入职手续，包括材料收集、档案建立等；2. 员工离职管理：协助完成员工离职，参与离职面谈，收集员工意见和建议等；3. 员工转正管理：根据员工试用期及时跟进转正审批流程及转正后手续流程；4. 员工续签管理：对合同/协议即将到期人员及时发起续签审批，安排续签签署，签署完成后对应资料归档；5. 文档与数据管理：维护员工劳动合同档案和数据库，确保信息准确、完整；6. 支持HR相关工作：根据需要，协助招聘、培训等其他人力资源相关工作', '员工关系支持、入离职手续办理、档案管理、招聘辅助、OD 组织发展支持', '本科及以上', '无强制专业限制', '本科及以上学历在读，26届及之后毕业生，可长期实习，每周实习4天以上，可实习3个月', '日常实习', '有人力资源管理师相关证书；游戏行业、人力资源相关实习经验', '100-150元/天', '46027', '46331', 'https://www.shixiseng.com/intern/inn_sr2srmahvd69?pcm=pc_SearchList', '员工关系类', '甲方（企业自有 HR 岗）');